define(['core/notification'],function(N){return{attach:function(c){setTimeout(function(){var iframes=document.querySelectorAll('iframe[src*="vimeo.com"]');iframes.forEach(function(iframe){player=new Vimeo.Player(iframe);player.getVideoId().then(function(id){if(String(id)===String(c.vimeoId)){if(iframe.classList.contains('vt-tracked'))return;iframe.classList.add('vt-tracked');var storageKey='vimeores_v'+c.vimeoId+'_c'+c.courseId;var savedTime=localStorage.getItem(storageKey);if(savedTime&&parseFloat(savedTime)>0){player.setCurrentTime(parseFloat(savedTime)).catch(function(err){console.log(err)})}player.on('timeupdate',function(data){localStorage.setItem(storageKey,data.seconds)});document.addEventListener('visibilitychange',function(){if(document.hidden){player.pause();player.setCurrentTime(0).then(function(){localStorage.setItem(storageKey,0);N.addNotification({message:'El video se reinició automáticamente por salir de la pantalla de estudio.',type:'warning'})})}})}}).catch(function(e){console.log(e)})})},1500)}}});
